(window.webpackJsonp=window.webpackJsonp||[]).push([[386],{1013:function(n,e){n.exports='\x3c!-- \ntitle: 15-CSS实战\nsort: \n--\x3e \n\n## 常用\n\n```css\ntext-align: justify;\nline-height: 1.3;\ntext-decoration: underline;\n\ndisplay:\nblock 块级元素\ninline 行内元素: !margin\ninline-block 行内块元素\nnone 隐藏\n\n/* 延时响应 */\ntransition: background-color 150ms;\ntext-decoration: none;\n/* x偏移量 | y偏移量 | 阴影模糊半径 | 阴影扩散半径 | 阴影颜色 */\nbox-shadow: 2px 2px 2px 1px rgba(0, 0, 0, 0.2);\n\n/* input默认内容 */\nplaceholder="XXXX"\n```\n\n## 响应式布局\n\n```css\n<link rel="stylesheet" href="common.css">\n<link media="(min-width: 800px)" rel="stylesheet" href="desktop.css">\n<link media="(max-width: 800px)" rel="stylesheet" href="mobile.css">\n\n/* 隐藏bar */\n#menu-checkbox:checked ~ .nav{\n  display: none;  \n}\n\n/* 映射至id对应的input标签 */\n<label id="menu-toggle" for="menu-checkbox">Click me</label>\n<input id="menu-checkbox" type="checkbox">\n```\n\n'}}]);